import threading
from datetime import datetime
from typing import Dict, List, Optional
from enum import Enum


class TransactionType(Enum):
    DEPOSIT = "deposit"
    WITHDRAWAL = "withdrawal"
    TRANSFER = "transfer"


class TransactionStatus(Enum):
    PENDING = "pending"
    COMPLETED = "completed"
    FAILED = "failed"


class Transaction:
    def __init__(self, transaction_id: str, transaction_type: TransactionType, 
                 amount: float, from_account: Optional[str] = None, 
                 to_account: Optional[str] = None, timestamp: Optional[datetime] = None):
        self.transaction_id = transaction_id
        self.transaction_type = transaction_type
        self.amount = amount
        self.from_account = from_account
        self.to_account = to_account
        self.timestamp = timestamp or datetime.now()
        self.status = TransactionStatus.PENDING


class Account:
    def __init__(self, account_id: str, initial_balance: float = 0.0):
        self.account_id = account_id
        self.balance = initial_balance
        self.lock = threading.Lock()
        self.transaction_history: List[Transaction] = []

    def get_balance(self) -> float:
        with self.lock:
            return self.balance

    def add_transaction(self, transaction: Transaction):
        with self.lock:
            self.transaction_history.append(transaction)


class FinancialProcessor:
    def __init__(self):
        self.accounts: Dict[str, Account] = {}
        self.global_lock = threading.Lock()

    def create_account(self, account_id: str, initial_balance: float = 0.0) -> Account:
        with self.global_lock:
            if account_id in self.accounts:
                raise ValueError(f"Account {account_id} already exists")
            account = Account(account_id, initial_balance)
            self.accounts[account_id] = account
            return account

    def get_account(self, account_id: str) -> Optional[Account]:
        return self.accounts.get(account_id)

    def process_transaction(self, transaction: Transaction) -> bool:
        try:
            if transaction.transaction_type == TransactionType.DEPOSIT:
                return self._process_deposit(transaction)
            elif transaction.transaction_type == TransactionType.WITHDRAWAL:
                return self._process_withdrawal(transaction)
            elif transaction.transaction_type == TransactionType.TRANSFER:
                return self._process_transfer(transaction)
            else:
                transaction.status = TransactionStatus.FAILED
                return False
        except Exception as e:
            transaction.status = TransactionStatus.FAILED
            return False

    def _process_deposit(self, transaction: Transaction) -> bool:
        if not transaction.to_account or transaction.amount <= 0:
            transaction.status = TransactionStatus.FAILED
            return False

        account = self.get_account(transaction.to_account)
        if not account:
            transaction.status = TransactionStatus.FAILED
            return False

        with account.lock:
            account.balance += transaction.amount
            transaction.status = TransactionStatus.COMPLETED
            account.add_transaction(transaction)
            return True

    def _process_withdrawal(self, transaction: Transaction) -> bool:
        if not transaction.from_account or transaction.amount <= 0:
            transaction.status = TransactionStatus.FAILED
            return False

        account = self.get_account(transaction.from_account)
        if not account:
            transaction.status = TransactionStatus.FAILED
            return False

        with account.lock:
            if account.balance < transaction.amount:
                transaction.status = TransactionStatus.FAILED
                return False
            account.balance -= transaction.amount
            transaction.status = TransactionStatus.COMPLETED
            account.add_transaction(transaction)
            return True

    def _process_transfer(self, transaction: Transaction) -> bool:
        if (not transaction.from_account or not transaction.to_account or 
            transaction.amount <= 0 or transaction.from_account == transaction.to_account):
            transaction.status = TransactionStatus.FAILED
            return False

        from_account = self.get_account(transaction.from_account)
        to_account = self.get_account(transaction.to_account)

        if not from_account or not to_account:
            transaction.status = TransactionStatus.FAILED
            return False

        accounts = sorted([from_account, to_account], key=lambda x: x.account_id)
        
        with accounts[0].lock:
            with accounts[1].lock:
                if from_account.balance < transaction.amount:
                    transaction.status = TransactionStatus.FAILED
                    return False
                
                from_account.balance -= transaction.amount
                to_account.balance += transaction.amount
                transaction.status = TransactionStatus.COMPLETED
                from_account.add_transaction(transaction)
                to_account.add_transaction(transaction)
                return True

    def process_batch_transactions(self, transactions: List[Transaction]) -> Dict[str, int]:
        results = {"completed": 0, "failed": 0}
        for transaction in transactions:
            if self.process_transaction(transaction):
                results["completed"] += 1
            else:
                results["failed"] += 1
        return results

    def get_account_balance(self, account_id: str) -> Optional[float]:
        account = self.get_account(account_id)
        if account:
            return account.get_balance()
        return None

    def get_transaction_history(self, account_id: str) -> Optional[List[Transaction]]:
        account = self.get_account(account_id)
        if account:
            with account.lock:
                return account.transaction_history.copy()
        return None